import{_ as o,C as l,o as s,c as n,E as e,w as a,a as r,a0 as d}from"./chunks/framework.CkNTPv-z.js";const v=JSON.parse('{"title":"Latvia Healthcare & HRT","description":"Transgender healthcare access in Latvia","frontmatter":{"layout":"doc","title":"Latvia Healthcare & HRT","description":"Transgender healthcare access in Latvia"},"headers":[],"relativePath":"europe/latvia/healthcare.md","filePath":"europe/latvia/healthcare.md","lastUpdated":null}'),c={name:"europe/latvia/healthcare.md"};function h(p,t,m,u,g,b){const i=l("Badge");return s(),n("div",null,[e(i,{variant:"red"},{default:a(()=>[...t[0]||(t[0]=[r("Very Limited Services",-1)])]),_:1}),e(i,{variant:"yellow"},{default:a(()=>[...t[1]||(t[1]=[r("Riga Central Clinic",-1)])]),_:1}),e(i,{variant:"green"},{default:a(()=>[...t[2]||(t[2]=[r("EU Prescription Portability",-1)])]),_:1}),t[3]||(t[3]=d('<h1 id="healthcare-hrt-in-latvia" tabindex="-1">Healthcare &amp; HRT in Latvia <a class="header-anchor" href="#healthcare-hrt-in-latvia" aria-label="Permalink to &quot;Healthcare &amp; HRT in Latvia&quot;">​</a></h1><h2 id="gatekeeping-model" tabindex="-1">Gatekeeping Model <a class="header-anchor" href="#gatekeeping-model" aria-label="Permalink to &quot;Gatekeeping Model&quot;">​</a></h2><p>Latvia has <strong>very limited</strong> transgender healthcare services:</p><ul><li><strong>Psychiatric diagnosis required</strong> — via a state-appointed medical commission</li><li><strong>Mandatory real-life experience</strong> period before HRT</li><li><strong>Surgery required</strong> for legal gender recognition (see Legal Rights)</li><li>Services concentrated in <strong>Riga</strong>; virtually none outside the capital</li></ul><h2 id="accessing-hrt" tabindex="-1">Accessing HRT <a class="header-anchor" href="#accessing-hrt" aria-label="Permalink to &quot;Accessing HRT&quot;">​</a></h2><h3 id="step-1-initial-consultation" tabindex="-1">Step 1: Initial Consultation <a class="header-anchor" href="#step-1-initial-consultation" aria-label="Permalink to &quot;Step 1: Initial Consultation&quot;">​</a></h3><ul><li>Contact the <strong>Riga East University Hospital</strong> (RAKUS) Psychiatry Clinic</li><li>Very limited number of specialists available</li><li>Long waiting times (3-8 months for initial appointment)</li><li>Latvian language required for most appointments</li></ul><h3 id="step-2-medical-commission" tabindex="-1">Step 2: Medical Commission <a class="header-anchor" href="#step-2-medical-commission" aria-label="Permalink to &quot;Step 2: Medical Commission&quot;">​</a></h3><ul><li>A multi-disciplinary commission evaluates your case</li><li>Must include psychiatrists, endocrinologists, and other specialists</li><li>Diagnosis of gender dysphoria required</li><li>Commission approval needed for treatment to proceed</li></ul><h3 id="step-3-hormone-therapy" tabindex="-1">Step 3: Hormone Therapy <a class="header-anchor" href="#step-3-hormone-therapy" aria-label="Permalink to &quot;Step 3: Hormone Therapy&quot;">​</a></h3><ul><li>HRT prescribed by an endocrinologist after commission approval</li><li>Limited choice of medications (only standard generics)</li><li>Monitoring every 3-6 months</li><li>Public healthcare covers basic HRT medications</li></ul><h2 id="key-clinics" tabindex="-1">Key Clinics <a class="header-anchor" href="#key-clinics" aria-label="Permalink to &quot;Key Clinics&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Clinic</th><th>Location</th><th>Services</th></tr></thead><tbody><tr><td>Riga East University Hospital (RAKUS)</td><td>Riga</td><td>Psychiatric assessment, medical commission</td></tr><tr><td>Pauls Stradins Clinical University Hospital</td><td>Riga</td><td>Endocrinology, HRT</td></tr><tr><td>Private psychiatrists</td><td>Riga</td><td>Assessment (shorter wait times, €60-100)</td></tr><tr><td>Private endocrinologists</td><td>Riga</td><td>HRT (limited availability)</td></tr></tbody></table><h2 id="prescription-portability" tabindex="-1">Prescription Portability <a class="header-anchor" href="#prescription-portability" aria-label="Permalink to &quot;Prescription Portability&quot;">​</a></h2><ul><li><strong>EU prescriptions</strong>: Valid in Latvia under EU mutual recognition</li><li><strong>Non-EU prescriptions</strong>: Must be verified by a Latvian doctor</li><li><strong>Importing medication</strong>: 3-month supply permitted with a doctor&#39;s letter</li><li><strong>Limited availability</strong>: Some HRT medications may need to be ordered from other EU countries</li><li><strong>Pharmacies</strong>: Large chain pharmacies (Mēness, Euroaptieka) in cities may stock HRT</li></ul><h2 id="surgical-options" tabindex="-1">Surgical Options <a class="header-anchor" href="#surgical-options" aria-label="Permalink to &quot;Surgical Options&quot;">​</a></h2><ul><li><strong>No gender-affirming surgeries available</strong> in Latvia</li><li>All surgeries must be arranged abroad (Thailand, Germany, Serbia, Belgium)</li><li>Public funding for surgery abroad is extremely limited</li><li>Most pay out-of-pocket for surgery abroad</li><li>Top surgery abroad: €5,000-8,000</li><li>Bottom surgery abroad: €15,000-25,000</li></ul><h2 id="costs" tabindex="-1">Costs <a class="header-anchor" href="#costs" aria-label="Permalink to &quot;Costs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Service</th><th>Latvian Resident</th><th>Non-Resident</th></tr></thead><tbody><tr><td>Psychiatric assessment</td><td>Free (public)</td><td>€80-120</td></tr><tr><td>Endocrinology visit</td><td>Free (public)</td><td>€60-100</td></tr><tr><td>HRT (monthly)</td><td>€10-25</td><td>€20-50</td></tr><tr><td>Medical commission</td><td>Free (public)</td><td>N/A</td></tr><tr><td>Surgery abroad</td><td>Not covered</td><td>N/A</td></tr></tbody></table><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://www.aslimnica.lv/" target="_blank" rel="noreferrer">Riga East University Hospital</a></li><li><a href="https://www.vm.gov.lv/" target="_blank" rel="noreferrer">Latvian Ministry of Health</a></li><li><a href="https://www.mozaika.lv/" target="_blank" rel="noreferrer">Mozaika (LGBTQ+ Organization)</a></li><li><a href="https://www.baltipride.com/" target="_blank" rel="noreferrer">Baltic Pride</a></li></ul>',21))])}const f=o(c,[["render",h]]);export{v as __pageData,f as default};
